import { createContext, useContext, useEffect, useMemo, useState } from "react";
import jwtDecode from "jwt-decode";
import api from "./api";

const AuthContext = createContext(null);
export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const t = localStorage.getItem("access_token");
        if (t) {
            try {
                const p = jwtDecode(t);
                const roles = Array.isArray(p.roles) ? p.roles :
                    (p.scope || p.role || "").split(" ").filter(Boolean);
                setUser({ username: p.sub || p.username, roles });
            } catch { localStorage.removeItem("access_token"); }
        }
        setLoading(false);
    }, []);

    const login = async (username, password) => {
        const { data } = await api.post("/api/auth/login", { username, password });
        const token = data.token || data.accessToken;
        localStorage.setItem("access_token", token);
        const p = jwtDecode(token);
        const roles = Array.isArray(p.roles) ? p.roles :
            (p.scope || p.role || "").split(" ").filter(Boolean);
        setUser({ username: p.sub || p.username, roles });
    };

    const logout = () => { localStorage.removeItem("access_token"); setUser(null); };
    return (
        <AuthContext.Provider value={useMemo(() => ({ user, loading, login, logout }), [user, loading])}>
            {children}
        </AuthContext.Provider>
    );
}
export const useAuth = () => useContext(AuthContext);
export const hasRole = (u, ...rs) => !!u?.roles && rs.some(r => u.roles.includes(r) || u.roles.includes(`ROLE_${r}`));
